mapper.select:
SELECT 
FROM bluenote_relation.relation_follower
WHERE followee_id = #{followeeId}
  AND relation_status = 'ACTIVE'

  AND (
    followed_at < #{cursorFollowedAt}
    OR (followed_at = #{cursorFollowedAt} AND follower_id < #{cursorFollowerId})
  )

ORDER BY followed_at DESC, follower_id DESC
LIMIT #{size}
